package io.scanbot.barcodesdk.plugin.reactnative.components.barcode_scanner_view

import android.Manifest
import android.app.Activity
import android.content.Context
import android.content.pm.PackageManager
import android.graphics.Color
import android.util.AttributeSet
import android.view.View
import android.view.ViewGroup
import android.widget.FrameLayout
import androidx.core.app.ActivityCompat
import androidx.lifecycle.DefaultLifecycleObserver
import androidx.lifecycle.LifecycleObserver
import androidx.lifecycle.LifecycleOwner
import androidx.lifecycle.findViewTreeLifecycleOwner
import com.facebook.react.bridge.ReactContext
import com.facebook.react.uimanager.UIManagerHelper
import io.scanbot.barcodesdk.plugin.reactnative.components.barcode_scanner_view.models.BarcodeItemOverlayViewConfig
import io.scanbot.barcodesdk.plugin.reactnative.components.barcode_scanner_view.models.CameraConfiguration
import io.scanbot.barcodesdk.plugin.reactnative.components.barcode_scanner_view.models.FinderViewConfiguration
import io.scanbot.barcodesdk.plugin.reactnative.components.barcode_scanner_view.models.PolygonStyleConfig
import io.scanbot.barcodesdk.plugin.reactnative.components.barcode_scanner_view.models.TextStyleConfig
import io.scanbot.barcodesdk.plugin.reactnative.extensions.toPx
import io.scanbot.common.Result
import io.scanbot.sdk.barcode.BarcodeItem
import io.scanbot.sdk.barcode.BarcodeScanner
import io.scanbot.sdk.barcode.BarcodeScannerResult
import io.scanbot.sdk.barcode.ui.BarcodePolygonsView
import io.scanbot.sdk.barcode.ui.BarcodeScannerView
import io.scanbot.sdk.barcode.ui.IBarcodeScannerFinderViewController
import io.scanbot.sdk.barcode.ui.IBarcodeScannerSelectionOverlayController
import io.scanbot.sdk.barcode.ui.IBarcodeScannerViewCallback
import io.scanbot.sdk.barcode_scanner.ScanbotBarcodeScannerSDK
import io.scanbot.sdk.camera.CaptureInfo
import io.scanbot.sdk.image.ImageRef
import io.scanbot.sdk_wrapper.barcode.extensions.uuid

class ScanbotBarcodeScannerView(
    context: Context, attrs: AttributeSet?, defStyleAttr: Int, defStyleRes: Int
) : FrameLayout(context, attrs, defStyleAttr, defStyleRes) {

    constructor(context: Context) : this(context, null)
    constructor(context: Context, attrs: AttributeSet?) : this(context, attrs, 0)
    constructor(context: Context, attrs: AttributeSet?, defStyleAttr: Int) : this(
        context, attrs, defStyleAttr, 0
    )

    companion object {
        private const val CAMERA_PERMISSION_REQUEST_CODE = 3331
        private const val INITIAL_FLASH_STATE = false
        private const val INITIAL_FRAME_PROCESSING_STATE = true
        private const val BARCODE_SCANNING_INTERVAL = 0L
    }

    var initializationError: Throwable =
        Result.ComponentUnavailableError("BarcodeScanner not initialized")

    var barcodeScanner: BarcodeScanner? = null
        get() {
            if (field == null) {
                sendEvent(BarcodeErrorEvent(initializationError))
            }
            return field
        }
        private set

    var scannerView: BarcodeScannerView? = null
        get() {
            if (field == null) {
                sendEvent(BarcodeErrorEvent(initializationError))
            }
            return field
        }
        private set

    var flashState: Boolean = INITIAL_FLASH_STATE
    var frameProcessingState: Boolean = INITIAL_FRAME_PROCESSING_STATE
    var polygonStyle = PolygonStyleConfig()
    var textStyle = TextStyleConfig()

    private var cameraPermissionRequested = false

    @Volatile
    private var barcodeItemOverlayViewBinders: MutableMap<String, BarcodeItemOverlayViewConfig>? =
        null

    private val lifecycleObserver: LifecycleObserver = object : DefaultLifecycleObserver {
        override fun onResume(owner: LifecycleOwner) {
            requestCameraPermissionIfNotGranted()
            super.onResume(owner)
        }

        override fun onDestroy(owner: LifecycleOwner) {
            owner.lifecycle.removeObserver(this)
            super.onDestroy(owner)
        }
    }

    init {
        layoutParams = ViewGroup.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.MATCH_PARENT,
        )
        setBackgroundColor(Color.BLACK)

        initBarcodeScannerView()
    }

    private fun initBarcodeScannerView() {
        try {
            ScanbotBarcodeScannerSDK(context).createBarcodeScanner().getOrThrow().let {
                barcodeScanner = it
                scannerView = BarcodeScannerView(context).apply {
                    initCamera()
                    initScanningBehavior(it, { result, _ ->
                        try {
                            result.getOrThrow().let { barcodeResult ->
                                if (barcodeResult.barcodes.isNotEmpty() && frameProcessingState) {
                                    sendEvent(BarcodeScannerResultEvent(barcodeResult))
                                    addBarcodeItemOverlayViewInitialBinder(barcodeResult)
                                }
                            }
                        } catch (ex: Throwable) {
                            sendEvent(BarcodeErrorEvent(ex))
                        }
                        false
                    }, object : IBarcodeScannerViewCallback {
                        override fun onCameraOpen() {
                            viewController.useFlash(flashState)
                            postDelayed({
                                viewController.isFrameProcessingEnabled = frameProcessingState
                            }, 500)
                        }

                        override fun onPictureTaken(image: ImageRef, captureInfo: CaptureInfo) {
                            // NO-OP
                        }

                        override fun onSelectionOverlayBarcodeClicked(barcodeItem: BarcodeItem) {
                            sendEvent(BarcodeSelectionResultEvent(barcodeItem))
                        }
                    })

                    viewController.barcodeScanningInterval = BARCODE_SCANNING_INTERVAL

                    configureFinderViewControllerWithDefaults(finderViewController)

                    cameraConfiguration.setPhysicalZoomRange(CameraConfiguration.DEFAULT_ZOOM_RANGE)

                    configureSelectionOverlayControllerWithDefaults(selectionOverlayController)
                }
                addView(scannerView)
            }
        } catch (ex: Throwable) {
            initializationError = ex
        }
    }

    private fun configureFinderViewControllerWithDefaults(finderViewController: IBarcodeScannerFinderViewController) {
        finderViewController.setStrokeColor(FinderViewConfiguration.DEFAULT_STROKE_COLOR)
        finderViewController.setOverlayColor(FinderViewConfiguration.DEFAULT_OVERLAY_COLOR)
        finderViewController.setFinderEnabled(FinderViewConfiguration.DEFAULT_FINDER_ENABLED)
        finderViewController.setStrokeWidth(
            FinderViewConfiguration.DEFAULT_STROKE_WIDTH.toPx(
                resources
            )
        )
        finderViewController.setFinderMinPadding(
            FinderViewConfiguration.DEFAULT_FINDER_MIN_PADDING.toPx(
                resources
            )
        )
        finderViewController.setFinderInset(
            FinderViewConfiguration.DEFAULT_FINDER_INSETS.left.toPx(resources),
            FinderViewConfiguration.DEFAULT_FINDER_INSETS.top.toPx(resources),
            FinderViewConfiguration.DEFAULT_FINDER_INSETS.right.toPx(resources),
            FinderViewConfiguration.DEFAULT_FINDER_INSETS.bottom.toPx(resources)
        )
        finderViewController.setRequiredAspectRatios(FinderViewConfiguration.DEFAULT_ASPECT_RATIO)
    }

    private fun configureSelectionOverlayControllerWithDefaults(selectionOverlayController: IBarcodeScannerSelectionOverlayController) {
        selectionOverlayController.setBarcodeAppearanceDelegate(object :
            BarcodePolygonsView.BarcodeAppearanceDelegate {
            override fun getPolygonStyle(
                defaultStyle: BarcodePolygonsView.BarcodePolygonStyle, barcodeItem: BarcodeItem
            ): BarcodePolygonsView.BarcodePolygonStyle {
                return defaultStyle.copy(
                    fillColor = PolygonStyleConfig.DEFAULT_FILL_COLOR,
                    fillHighlightedColor = PolygonStyleConfig.DEFAULT_FILL_COLOR,
                    strokeColor = PolygonStyleConfig.DEFAULT_STROKE_COLOR,
                    strokeHighlightedColor = PolygonStyleConfig.DEFAULT_STROKE_COLOR
                )
            }

            override fun getTextViewStyle(
                defaultStyle: BarcodePolygonsView.BarcodeTextViewStyle, barcodeItem: BarcodeItem
            ): BarcodePolygonsView.BarcodeTextViewStyle {
                return defaultStyle.copy(
                    textColor = TextStyleConfig.DEFAULT_TEXT_COLOR,
                    textHighlightedColor = TextStyleConfig.DEFAULT_TEXT_COLOR,
                    textContainerColor = TextStyleConfig.DEFAULT_TEXT_CONTAINER_COLOR,
                    textContainerHighlightedColor = TextStyleConfig.DEFAULT_TEXT_CONTAINER_COLOR,
                    textFormat = TextStyleConfig.DEFAULT_TEXT_FORMAT
                )
            }
        })
    }

    override fun onAttachedToWindow() {
        super.onAttachedToWindow()
        if (scannerView?.viewController != null) {
            findViewTreeLifecycleOwner()?.let {
                it.lifecycle.addObserver(lifecycleObserver)
                scannerView?.viewController?.setLifecycleOwner(it)
            } ?: run {
                sendEvent(BarcodeErrorEvent(Result.ComponentUnavailableError("No lifecycle owner found")))
            }
        } else {
            sendEvent(BarcodeErrorEvent(Result.ComponentUnavailableError("No scanner view controller found")))
        }
    }

    override fun requestLayout() {
        super.requestLayout()
        post {
            layoutView()
        }
    }

    private fun View.layoutView() {
        measure(
            MeasureSpec.makeMeasureSpec(measuredWidth, MeasureSpec.EXACTLY),
            MeasureSpec.makeMeasureSpec(measuredHeight, MeasureSpec.EXACTLY)
        )
        layout(left, top, right, bottom)
    }

    fun sendEvent(event: BaseEvent) {
        val surfaceId = UIManagerHelper.getSurfaceId(this)

        event.send(surfaceId, context as ReactContext, id)
    }

    private fun requestCameraPermissionIfNotGranted() {
        val activity: Activity = (context as ReactContext).currentActivity ?: return

        if (!cameraPermissionRequested && ActivityCompat.checkSelfPermission(
                activity, Manifest.permission.CAMERA
            ) != PackageManager.PERMISSION_GRANTED
        ) {
            // shouldShowRequestPermissionRationale can be changed from another place in the app,
            // that's why we are using custom flag
            cameraPermissionRequested = true

            ActivityCompat.requestPermissions(
                activity, arrayOf(Manifest.permission.CAMERA), CAMERA_PERMISSION_REQUEST_CODE
            )
        }
    }

    fun setOverlayAppearance() {
        scannerView?.selectionOverlayController?.setBarcodeAppearanceDelegate(object :
            BarcodePolygonsView.BarcodeAppearanceDelegate {
            override fun getPolygonStyle(
                defaultStyle: BarcodePolygonsView.BarcodePolygonStyle, barcodeItem: BarcodeItem
            ): BarcodePolygonsView.BarcodePolygonStyle {
                val overlayViewConfig = getBarcodeItemOverlayViewBinder(barcodeItem)

                return defaultStyle.copy(
                    fillColor = overlayViewConfig?.polygonColorParsed ?: polygonStyle.fillColor!!,
                    strokeColor = overlayViewConfig?.strokeColorParsed
                        ?: polygonStyle.strokeColor!!,
                )
            }

            override fun getTextViewStyle(
                defaultStyle: BarcodePolygonsView.BarcodeTextViewStyle, barcodeItem: BarcodeItem
            ): BarcodePolygonsView.BarcodeTextViewStyle {
                val overlayViewConfig = getBarcodeItemOverlayViewBinder(barcodeItem)

                return defaultStyle.copy(
                    textColor = overlayViewConfig?.textColorParsed ?: textStyle.textColor!!,
                    textContainerColor = overlayViewConfig?.textContainerColorParsed
                        ?: textStyle.textContainerColor!!,
                    textFormat = textStyle.textFormat!!
                )
            }
        })

        scannerView?.selectionOverlayController?.setBarcodeStringDelegate(object :
            BarcodePolygonsView.BarcodeStringDelegate {
            override fun overrideString(string: String, barcodeItem: BarcodeItem): String {
                val overlayViewConfig = getBarcodeItemOverlayViewBinder(barcodeItem)

                return overlayViewConfig?.text ?: string
            }
        })
    }

    private fun getBarcodeItemOverlayViewBinder(barcodeItem: BarcodeItem): BarcodeItemOverlayViewConfig? {
        return barcodeItemOverlayViewBinders?.get(barcodeItem.uuid())?.let {
            // If caching is disabled use general settings as starting point (not last bind) after refreshRate
            if (it.refreshRate > 0 && it.lastBind > 0 && (System.currentTimeMillis() - it.lastBind >= it.refreshRate)) {
                null
            } else {
                it
            }
        }
    }

    private fun addBarcodeItemOverlayViewInitialBinder(barcodeResult: BarcodeScannerResult) {
        barcodeItemOverlayViewBinders?.let { bindersList ->
            barcodeResult.barcodes.forEach { barcodeItem ->
                val barcodeItemUuid = barcodeItem.uuid()

                if (!bindersList.contains(barcodeItemUuid)) {
                    bindersList[barcodeItemUuid] =
                        BarcodeItemOverlayViewConfig(text = BarcodeItemOverlayViewConfig.LOADING_TEXT)
                }
            }
        }
    }

    fun updateBarcodeItemOverlayViewBinder(
        barcodeItemUuid: String, barcodeItemOverlayViewConfig: BarcodeItemOverlayViewConfig
    ) {
        barcodeItemOverlayViewBinders?.let { bindersList ->
            if (bindersList.contains(barcodeItemUuid)) {
                bindersList[barcodeItemUuid] = barcodeItemOverlayViewConfig
            }
        }
    }

    fun setBarcodeItemOverlayViewBinder(enabled: Boolean) {
        if (enabled) {
            if (barcodeItemOverlayViewBinders == null) {
                barcodeItemOverlayViewBinders = mutableMapOf()
            }
        } else {
            barcodeItemOverlayViewBinders?.clear()
            barcodeItemOverlayViewBinders = null
        }
    }
}
